mapper.select:
SELECT e.ID, e.CATEGORY_ID, e.MATERIAL_CODE, e.MATERIAL_NAME, e.PURCHASE_TYPE_CODE, e.PURCHASE_TYPE_NAME, e.SPECIFICATION_MODEL, e.BRAND, e.UNIT_CODE, e.UNIT_NAME, e.MNEMONIC_CODE, e.STATUS, e.CREATE_BY, e.CREATE_BY_NAME, e.CREATE_TIME, e.UPDATE_BY, e.UPDATE_BY_NAME, e.UPDATE_TIME, e.DEL_FLAG, e.DELETE_BY, e.DELETE_BY_NAME, e.DELETE_TIME, c.CATEGORY_NAME, CASE WHEN c3.CATEGORY_NAME IS NOT NULL AND c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c3.CATEGORY_NAME || '/' || c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c2.CATEGORY_NAME IS NOT NULL AND c.CATEGORY_NAME IS NOT NULL THEN c2.CATEGORY_NAME || '/' || c.CATEGORY_NAME WHEN c.CATEGORY_NAME IS NOT NULL THEN c.CATEGORY_NAME ELSE '' END AS CATEGORY_PATH FROM E_MATERIAL_CODE e LEFT JOIN E_MATERIAL_CATEGORY c ON e.CATEGORY_ID = c.ID AND c.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c2 ON c.PARENT_ID = c2.ID AND c2.DEL_FLAG = 0 LEFT JOIN E_MATERIAL_CATEGORY c3 ON c2.PARENT_ID = c3.ID AND c3.DEL_FLAG = 0
e.DEL_FLAG = 0
AND e.CATEGORY_ID = #{categoryId}
AND e.MATERIAL_CODE LIKE #{materialCodePattern}
AND e.MATERIAL_NAME LIKE #{materialNamePattern}
ORDER BY e.CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_CODE
WHERE MATERIAL_CODE = #{materialCode}
AND DEL_FLAG = 0

    AND ID != #{id}
